import { Link } from "react-router-dom";

const Sidebar = () => {
  return (
    <div style={{width:"220px",background:"#1e293b",color:"white",height:"100vh",padding:"20px"}}>

      <h2>URMS</h2>

      <ul style={{listStyle:"none",padding:0}}>

        <li><Link to="/dashboard">Dashboard</Link></li>
        <li><Link to="/resources">Browse Resources</Link></li>
        <li><Link to="/my-resources">My Resources</Link></li>
        <li><Link to="/requests">Request History</Link></li>
        <li><Link to="/notifications">Notifications</Link></li>
        <li><Link to="/profile">Profile</Link></li>

      </ul>

    </div>
  );
};

export default Sidebar;
